Pour démarrer un nouveau processus en C++ avec un descripteur de fichier connecté à son entrée et à sa sortie, vous pouvez utiliser la bibliothèque `<unistd.h>` pour les fonctions POSIX. Voici un exemple :

```cpp
#include <iostream>
#include <unistd.h>
#include <sys/wait.h>
#include <cstdlib>

int main() {
    pid_t pid = fork();

    if (pid == -1) {
        std::cerr << "Échec du fork()" << std::endl;
        exit(1);
    }

    if (pid == 0) { // Processus enfant
        // Rediriger l'entrée et la sortie vers le même descripteur
        close(STDIN_FILENO);
        dup2(STDOUT_FILENO, STDIN_FILENO);

        // Exécuter le programme
        execlp("echo", "echo", "Bonjour, monde !", (char *) 0);
        perror("execlp");
        _exit(1);
    } else { // Processus parent
        int status;
        waitpid(pid, &status, 0);
        if (WIFEXITED(status)) {
            std::cout << "Le processus a terminé avec le code de sortie " << WEXITSTATUS(status) << std::endl;
        }
    }

    return 0;
}
```

Cet exemple crée un nouveau processus, redirige l'entrée et la sortie vers le même descripteur, et exécute le programme "echo" avec un message.
